import React from 'react';

const Footer = () => {
  return (
    <footer className="bg-neutral-900 border-t border-neutral-800/50 w-full py-12 px-8 relative z-10">
      <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-6">
        <div className="flex flex-col items-center md:items-start gap-2">
          <span className="text-lg font-bold text-neutral-200 font-headline tracking-tighter">CINE-AI</span>
          <p className="font-inter text-xs uppercase tracking-widest text-neutral-500">© 2024 CINE-AI. Built with AI.</p>
        </div>
        <div className="flex gap-8">
          <a className="font-inter text-xs uppercase tracking-widest text-neutral-500 hover:text-red-500 transition-colors opacity-80 hover:opacity-100" href="#">Help Center</a>
          <a className="font-inter text-xs uppercase tracking-widest text-neutral-500 hover:text-red-500 transition-colors opacity-80 hover:opacity-100" href="#">Privacy Policy</a>
          <a className="font-inter text-xs uppercase tracking-widest text-neutral-500 hover:text-red-500 transition-colors opacity-80 hover:opacity-100" href="#">Terms of Service</a>
          <a className="font-inter text-xs uppercase tracking-widest text-neutral-500 hover:text-red-500 transition-colors opacity-80 hover:opacity-100" href="#">Social</a>
        </div>
      </div>
    </footer>
  );
};

export default Footer;
